# Commander AI Lab - Full Fresh Installer
# Deploys ALL 119 project files
# Usage: powershell -ExecutionPolicy Bypass -File install-commander-ai-lab.ps1

$ErrorActionPreference = "Stop"
$targetDir = 'D:\ForgeCommander\commander-ai-lab'

Write-Host ''
Write-Host '=======================================================' -ForegroundColor Cyan
Write-Host '  Commander AI Lab - Full Fresh Installer' -ForegroundColor Cyan
Write-Host '  v13: Full Stack + ML Training + PPO RL + Tournament Eval' -ForegroundColor Cyan
Write-Host '=======================================================' -ForegroundColor Cyan
Write-Host ''

if (-not (Test-Path $targetDir)) {
    New-Item -ItemType Directory -Path $targetDir -Force | Out-Null
    Write-Host ('  Created: ' + $targetDir) -ForegroundColor Green
} else {
    Write-Host ('  Target exists: ' + $targetDir) -ForegroundColor Yellow
}

function Install-B64 {
    param([string]$R, [string]$B)
    $fp = Join-Path $targetDir $R
    $d = Split-Path $fp -Parent
    if (-not (Test-Path $d)) {
        New-Item -ItemType Directory -Path $d -Force | Out-Null
    }
    $clean = $B -replace '[\r\n\s]',''
    $bytes = [Convert]::FromBase64String($clean)
    [IO.File]::WriteAllBytes($fp, $bytes)
    $kb = [math]::Round($bytes.Length / 1024, 1)
    Write-Host ('  [OK] ' + $R + ' (' + $kb + ' KB)') -ForegroundColor Green
}

Write-Host ('  Target: ' + $targetDir) -ForegroundColor Gray
Write-Host '  Files:  119' -ForegroundColor Gray
Write-Host ''
Write-Host '  Installing files...' -ForegroundColor White
Write-Host ''
